import { IconComponent } from './icon.component';
const meta = {
    title: 'Design System/Icon',
    component: IconComponent,
    tags: ['autodocs'],
    parameters: { layout: 'padded' },
    argTypes: {
        name: { control: 'text' },
        size: { control: { type: 'select', options: [16, 20, 24, 32] } },
    },
    args: {
        name: 'search',
        size: 24,
    },
};
export default meta;
// ── Single icon (controls) ────────────────────────────────────
export const Default = {};
// ── All icons at a glance ─────────────────────────────────────
const ALL_ICONS = [
    'search', 'home', 'buyers', 'shield', 'tools', 'settings', 'chart',
    'help', 'bell',
    'contract', 'checklist',
    'arrow-right', 'chevron-right', 'chevron-down',
    'close', 'check', 'plus', 'edit', 'trash',
    'info-circle', 'warning-triangle', 'check-circle', 'error-circle',
    'filter', 'download', 'upload', 'eye', 'eye-off',
    'calendar', 'clock', 'mail', 'user', 'external-link',
];
export const AllIcons = {
    render: () => ({
        props: { icons: ALL_ICONS },
        template: `
      <div style="display: flex; flex-wrap: wrap; gap: 24px; padding: 16px;">
        @for (icon of icons; track icon) {
          <div style="display: flex; flex-direction: column; align-items: center; gap: 8px; width: 80px;">
            <ds-icon [name]="icon" [size]="24" />
            <span style="font-size: 11px; color: #767676; text-align: center; word-break: break-all;">{{ icon }}</span>
          </div>
        }
      </div>
    `,
    }),
};
// ── Sizes ─────────────────────────────────────────────────────
export const Sizes = {
    render: () => ({
        props: {},
        template: `
      <div style="display: flex; align-items: center; gap: 32px; padding: 16px;">
        <div style="display: flex; flex-direction: column; align-items: center; gap: 8px;">
          <ds-icon name="search" [size]="16" />
          <span style="font-size: 11px; color: #767676;">16px</span>
        </div>
        <div style="display: flex; flex-direction: column; align-items: center; gap: 8px;">
          <ds-icon name="search" [size]="20" />
          <span style="font-size: 11px; color: #767676;">20px</span>
        </div>
        <div style="display: flex; flex-direction: column; align-items: center; gap: 8px;">
          <ds-icon name="search" [size]="24" />
          <span style="font-size: 11px; color: #767676;">24px</span>
        </div>
        <div style="display: flex; flex-direction: column; align-items: center; gap: 8px;">
          <ds-icon name="search" [size]="32" />
          <span style="font-size: 11px; color: #767676;">32px</span>
        </div>
      </div>
    `,
    }),
};
// ── Color via currentColor ────────────────────────────────────
export const Colors = {
    render: () => ({
        props: {},
        template: `
      <div style="display: flex; align-items: center; gap: 24px; padding: 16px;">
        <ds-icon name="shield" [size]="32" style="color: #1A73E8;" />
        <ds-icon name="check-circle" [size]="32" style="color: #34A853;" />
        <ds-icon name="warning-triangle" [size]="32" style="color: #FBBC04;" />
        <ds-icon name="error-circle" [size]="32" style="color: #EA4335;" />
        <ds-icon name="info-circle" [size]="32" style="color: #767676;" />
      </div>
    `,
    }),
};
